<template>
    <v-container>
        <PagePath />
        <div class="content">
            <div class="btn_area">
                <v-btn elevation="3" color="primary" outlined @click="popupView(true)"> 추가 </v-btn>
                <v-btn elevation="3" :disabled="!this.selectInfo.PEER_IDENTIFICATION_ID" color="primary" outlined @click="popupDeleteView(true, true)"> 삭제 </v-btn>
                <v-btn elevation="3" color="primary" outlined @click="popupDeleteView(true, false)"> 전체 삭제 </v-btn>
            </div>
            <v-data-table
                :headers="headers"
                :items-per-page="pageSize"
                :items="dataList"
                no-data-text="데이터가 존재하지 않습니다."
                hide-default-footer
            >
                <template #item="{ item, index }">
                    <tr @click="selectList(item)" :class="selectInfo.PEER_IDENTIFICATION_ID === item.PEER_IDENTIFICATION_ID ? 'active' : ''">
                        <td>{{ index + 1 }}</td>
                        <td>{{ item.MODEL_NAME }}</td>
                        <td>{{ item.DRONE_ID }}</td>
                        <!-- <td><img src="@/assets/setting/ico_drone_sample.svg" /></td> -->
                        <td><img :src="getImgaeUri(item.IMAGE_URI)" width="100"/></td>
                        <td>{{ getTimestamp(item.CREATED) }}</td>
                    </tr>
                </template>
            </v-data-table>
            <v-col class="pagination">
                <v-pagination v-model="pageNo" :length="numOfPages" :total-visible="pageSize" />
            </v-col>
        </div>
        <AddDronePopup v-if="isPopupOpen" @popupCloseYes="onUpdate" @popupCloseNo="onUpdateCancel"/>
        <DeleteConfirmPopup v-if="isDeletePopupOpen" :defaultView="isDeleteOne" @popupCloseYes="onDelete" @popupCloseNo="onDeleteCancel" />

        <AlertModal :params="alertModalParams"></AlertModal>
    </v-container>
</template>

<script>
// import peerIdentifyList from '@/data/peerIdentifyList';
import PagePath from '@/components/widget/PagePath';
import AddDronePopup from '@/components/popup/setting/AddDrone';
import DeleteConfirmPopup from '@/components/popup/common/DeleteConfirm';

import * as Consts from "@/common/Consts";
import * as DateUtil from "@/common/DateUtil";
import * as LogUtil from "@/common/LogUtil";
import * as PeerIdentification from "@/rest/PeerIdentification";

import AlertModal from '@/components/modal/AlertModal';

export default {
    components: {
      PagePath,
      AddDronePopup,
      DeleteConfirmPopup,
      AlertModal
    },
    data: () => ({
      alertModalParams: { isOpened: false, title: '', message: ''},
      dataList: [],
      pageNo: 1,
      pageSize: 5,
      
      selectInfo: {},
      isPopupOpen: false,
      isDeletePopupOpen: false,
      isDeleteOne: false,
      headers: [
          { text: 'No', sortable: false },
          { text: '모델명', value: 'MODEL_NAME', sortable: false },
          { text: '드론ID', value: 'DRONE_ID' },
          { text: '사진', value: 'IMAGE_URI', sortable: false },
          { text: '등록 시간', value: 'CREATED' },
      ],
    }),
    beforeMount() {
      this.initDataList();
    },
    computed: {
      numOfPages() {
        return Math.ceil(this.dataList.length / this.pageSize);
      },
    },
    methods: {
      showAlertModal(msg) {
        this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
      },
      getTimestamp(timestamp) {
        return DateUtil.getTimestamp(timestamp);
      },
      selectList(select) {
          if (this.selectInfo === select) this.selectInfo = {};
          else this.selectInfo = select;
      },
      popupView(view) {
          this.isPopupOpen = view;
      },
      popupDeleteView(view, isDeleteOne) {
          this.isDeletePopupOpen = view;
          this.isDeleteOne = isDeleteOne;
      },
      onDelete() {
        this.isDeletePopupOpen = false;
        if(this.isDeleteOne) {
          this.deleteOne();
        } else {
          this.deleteAll();
        }
      },
      deleteOne() {
        LogUtil.debug("PeerIdentify: deleteOne(): this.selectInfo=", this.selectInfo);
        if(this.selectInfo.PEER_IDENTIFICATION_ID !== undefined) {
          PeerIdentification.deleteOne({
            PEER_IDENTIFICATION_ID: this.selectInfo.PEER_IDENTIFICATION_ID
          }).then(res => {
            if(res.data.RES_CODE>=0) {
              LogUtil.debug("res.data.RES_CODE=", res.data.RES_CODE);
              this.selectInfo = {};
              this.isDeletePopupOpen = false;
              this.initDataList();
            } else {
              this.showAlertModal(res.data.RES_MSG);
            }
          }).catch(e => {
            LogUtil.error("error=", e);
            this.showAlertModal(e);
          }).finally(() => {
          });
        }
      },
      deleteAll() {
        this.isDeletePopupOpen = false;
        let ID_LIST = [];
        this.dataList.forEach((item)=>{
          ID_LIST.push(item.PEER_IDENTIFICATION_ID);
        });
        LogUtil.debug("PeerIdentify: deleteAll(): this.selectInfo=", this.selectInfo);
        if(this.selectInfo.PEER_IDENTIFICATION_ID !== undefined) {
          PeerIdentification.deleteMulti({
            ID_LIST: ID_LIST
          }).then(res => {
            if(res.data.RES_CODE>=0) {
              LogUtil.debug("res.data.RES_CODE=", res.data.RES_CODE);
              this.selectInfo = {};
              this.isDeletePopupOpen = false;
              this.initDataList();
            } else {
              this.showAlertModal(res.data.RES_MSG);
            }
          }).catch(e => {
            LogUtil.error("error=", e);
            this.showAlertModal(e);
          }).finally(() => {
          });
        }
      },
      onDeleteCancel() {
        this.isDeletePopupOpen = false;
      },
      onUpdate() {
        this.isPopupOpen = false;
        this.initDataList();
        LogUtil.debug("PeerIdentify: onUpdate()");
      },
      onUpdateCancel() {
        this.isPopupOpen = false;
        LogUtil.debug("PeerIdentify: onUpdateCancel()");
      },
      initDataList(condition) {
        let options = {
          conditions: [
            // { clause: 'and', name: 'MEMBER_TYPE', operator: '=', value: 'H'},
          ],
          orderBys: [
            { name: 'MODEL_NAME', operator: 'asc'}
          ],
          paging: { pageNo: 1, pageSize: this.pageSize }
        };
        if(condition != null) options.conditions.push(condition);

        PeerIdentification.listByCondition(options).then(res => {
          if(res.data.RES_CODE>=0) {
            this.dataList = res.data.ITEMS;
            // this.dataList.forEach((item)=>{
            //   if(item.DETECT_RADIUS != null && item.DEFENSE_RADIUS != null && item.CENTER_RADIUS != null ) {
            //     item.CIRCLE_INFO = '(' + item.DETECT_RADIUS + ',' + item.DEFENSE_RADIUS + ',' + item.CENTER_RADIUS + ')';
            //   }
            // });
            LogUtil.debug("PeerIdentify: initDataList(): this.dataList=", this.dataList);
          } else {
            this.showAlertModal(res.data.RES_MSG);
          }
        }).catch(e => {
          LogUtil.error("error=", e);
          this.showAlertModal(e);
        }).finally(() => {
        });
      },
      getImgaeUri(imageUri) {
        return Consts.SERVER_URL + imageUri;
      },
    },
};
</script>

<style lang="scss" scoped>
.content {
    width: 1120px;
    .btn_area {
        margin-bottom: 29px;
        button + button {
            margin-left: 10px;
        }
    }
    .pagination {
        padding: 0;
        margin-top: 50px;
    }
}
</style>

