const isProduction = false;

const debug = (...params) => {
    if (isProduction) return;
    let str = '';
    params.forEach((param)=>{
      str = str + ( param instanceof String ? param : JSON.stringify(param) ); 
    });
    console.log(str);
};

const error = (...params) => {
    if (isProduction) return;
    let str = '';
    params.forEach((param)=>{
      str = str + ( param instanceof String ? param : JSON.stringify(param) ); 
    });
    console.error(str);
};

export { debug, error };