<template>
    <div class="popup_wrap">
        <div class="popup_content">
            <p class="popup_title">
                {{ popupStep === 1 ? '추가' : '드론 모델명 찾기' }}
            </p>
            <div class="input_area" v-show="popupStep === 1">
                <dl>
                    <dt>모델명</dt>
                    <dd>
                        <v-text-field v-model="model.MODEL_NAME" outlined hide-details class="white find" readonly @click="stepChange(2)" />
                    </dd>
                </dl>
                <dl>
                    <dt>드론ID</dt>
                    <dd>
                        <v-text-field v-model="model.DRONE_ID" outlined hide-details class="white" />
                    </dd>
                </dl>
            </div>
            <div class="find_area" v-show="popupStep === 2">
                <div class="search">
                    <v-text-field v-model="modelName" outlined hide-details class="white find" @keydown.enter="doSearch" />
                    <v-btn color="primary" outlined elevation="3" @click="doSearch">찾기</v-btn>
                </div>
                <div class="find_list">
                    <p class="tit">모델명</p>
                    <ul>
                        <li v-for="(item, index) in dataList" :class="selectedModelIndex === index ? 'active' : ''" :key="index" 
                          @click="modelSelect(index)">
                            {{ item.MODEL_NAME }}
                        </li>
                    </ul>
                </div>
            </div>
            <div v-if="popupStep === 1" class="btn_area">
                <v-btn elevation="3" :disabled="!validation" color="primary" @click="doSave"> 확인 </v-btn>
                <v-btn outlined plain elevation="3" @click="popupCloseNo">취소</v-btn>
            </div>
            <div v-if="popupStep === 2" class="btn_area">
                <v-btn elevation="3" :disabled="selectedModelIndex === -1" color="primary" @click="stepChange(1)"> 확인 </v-btn>
                <v-btn
                    outlined
                    plain
                    elevation="3"
                    @click="
                        () => {
                            selectedModelIndex = 0;
                            stepChange(1);
                        }
                    "
                    >취소</v-btn
                >
            </div>
        </div>
        <AlertModal :params="alertModalParams"></AlertModal>
    </div>
</template>
<script>
import * as Consts from "@/common/Consts";
import * as LogUtil from "@/common/LogUtil";
import * as IdentificationLibrary from "@/rest/IdentificationLibrary";
import * as PeerIdentification from "@/rest/PeerIdentification";

import AlertModal from '@/components/modal/AlertModal';

export default {
  components: {
    AlertModal
  },
  data: () => ({
    alertModalParams: { isOpened: false, title: '', message: ''},
    dataList: [],

    model: {},

    modelName: null,
    // droneId: null,
    selectedModel: null,
    selectedModelIndex: -1,
    
    validation: false,
    popupStep: 1,
  }),
  mounted() {
    this.initDataList();
  },
  updated() {
      this.validationCheck();
  },
  methods: {
    showAlertModal(msg) {
      this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
    },
    popupCloseYes() {
      LogUtil.debug('AddDrone: popupCloseYes(): this.selectedModel=', this.selectedModel);
      this.$emit('popupCloseYes', false);
    },
    doSave() {
      LogUtil.debug('AddDrone: doSave(): this.model=', this.model);
      let model = {
        PEER_IDENTIFICATION_ID: this.model.PEER_IDENTIFICATION_ID != null ? this.model.PEER_IDENTIFICATION_ID : -1,
        MODEL_NAME: this.model.MODEL_NAME,
        DRONE_ID: this.model.DRONE_ID,
        IMAGE_URI: this.selectedModel.IMAGE_URI,
      }
      LogUtil.debug('AddDrone: doSave(): model=', model);
      PeerIdentification.save(model).then(res => {
        if(res.data.RES_CODE>=0) {
          LogUtil.debug('AddDrone: doSave(): res.data.RES_CODE=', res.data);
          if(this.model.PEER_IDENTIFICATION_ID === -1) {
            this.model.PEER_IDENTIFICATION_ID = res.data.insertId;
            LogUtil.debug('AddDrone: doSave(): this.model=', this.model);
          } else {
            LogUtil.debug('AddDrone: doSave(): this.model.PEER_IDENTIFICATION_ID=', this.model.PEER_IDENTIFICATION_ID);
          }
          this.$emit('popupCloseYes', false);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
      });
    },
    popupCloseNo() {
      LogUtil.debug('AddDrone: popupCloseNo()');
      this.$emit('popupCloseNo', false);
    },
    stepChange(num) {
      this.popupStep = num;
      if (num === 1) {
        if (this.selectedModelIndex !== -1) {
          this.selectedModel = this.dataList[this.selectedModelIndex];
          this.model.MODEL_NAME = this.selectedModel.MODEL_NAME;
        }
        LogUtil.debug('AddDrone: stepChange(): this.selectedModel=', this.selectedModel);
      } else if (num === 2) {
        this.selectedModelIndex = -1;
        LogUtil.debug('AddDrone: stepChange(): num=', num);
      }
    },
    validationCheck() {
      this.validation = this.model.DRONE_ID && this.model.MODEL_NAME;
    },
    modelSelect(index) {
      LogUtil.debug('AddDrone: modelSelect(): index=', index);
      if (this.selectedModelIndex === index) {
        this.selectedModelIndex = 0;
        return;
      }
      this.selectedModelIndex = index;
    },
    initDataList(condition) {
      let options = {
        conditions: [
          // { clause: 'and', name: 'MEMBER_TYPE', operator: '=', value: 'H'},
        ],
        orderBys: [
          { name: 'MODEL_NAME', operator: 'asc'}
        ],
        paging: { pageNo: 1, pageSize: this.pageSize }
      };
      if(condition != null) options.conditions.push(condition);

      IdentificationLibrary.listByCondition(options).then(res => {
        if(res.data.RES_CODE>=0) {
          this.dataList = res.data.ITEMS;
          // this.dataList.forEach((item)=>{
          //   if(item.DETECT_RADIUS != null && item.DEFENSE_RADIUS != null && item.CENTER_RADIUS != null ) {
          //     item.CIRCLE_INFO = '(' + item.DETECT_RADIUS + ',' + item.DEFENSE_RADIUS + ',' + item.CENTER_RADIUS + ')';
          //   }
          // });
          LogUtil.debug("AddDrone: initDataList(): this.dataList=", this.dataList);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
      });
    },
    doSearch() {
      if(this.modelName != null) {
        let condition = { clause: 'and', name: 'MODEL_NAME', operator: 'like', value: this.modelName };
        this.initDataList(condition);
      }
    }
  },
};
</script>

<style lang="scss" scoped>
input {
    &:read-only {
        cursor: pointer !important;
    }
}
.popup_wrap {
    .popup_content {
        width: 400px;
        padding: 0 10px;
        .popup_title {
            @include centerAlign();
            height: 52px;
            border-bottom: 1px solid #ccc;
            font: {
                size: 20px;
                weight: 600;
            }
        }
        .input_area {
            height: 156px;
            padding: 28px 48px 34px;
            border-bottom: 1px solid #ccc;
            dl {
                @include centerAlign();
                dt {
                    padding-right: 10px;
                    font: {
                        size: 15px;
                        weight: 500;
                    }
                }
                dd {
                    .find {
                        background: url('@/assets/setting/ico_find.svg') no-repeat 96% center;
                    }
                }
                & + dl {
                    margin-top: 19px;
                }
            }
        }
        .find_area {
            padding: 20px 20px 30px;
            border-bottom: 1px solid #ccc;
            .search {
                @include centerAlign();
                width: 300px;
                margin: 0 20px;
                button {
                    margin-left: 10px;
                }
            }
            .find_list {
                margin-top: 10px;
                border: 1px solid $color-main03;
                font: {
                    size: 15px;
                    weight: 400;
                }
                .tit {
                    @include centerAlign();
                    height: 30px;
                    border-bottom: 1px solid $color-main03;
                    background: #ccc;
                    font: {
                        weight: 600;
                    }
                }
                ul {
                    overflow-y: auto;
                    height: 320px;
                    li {
                        @include centerAlign();
                        height: 30px;
                        border-bottom: 1px solid $color-main03;
                        cursor: pointer;
                        &.active {
                            background-color: $color-main01;
                            color: $color-main04;
                        }
                        &:last-child {
                            border-bottom: 0 none;
                        }
                    }
                }
            }
        }
        .btn_area {
            @include centerAlign();
            width: 100%;
            button + button {
                margin-left: 14px;
            }
        }
    }
}
</style>
